var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 제 9 포격전대 메이즈\\n업무 보고","JPN":"管理局第9砲撃戦隊メイズ\\n業務報告","ENG":"The 9th Administration Artillery Division, Maze\\nDuty reporting","TWN":"管理局第9砲擊戰隊 梅茲\\n報告任務中"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"슬슬 업무 보고 시간이네. 류드밀라도 지금쯤이면 돌아왔으려나.","JPN":"そろそろ業務報告の時間ね。リュドミラも戻っている頃かしら。","ENG":"It's almost time to report back to Lyudmila. I wonder if she's back.","TWN":"快到報告任務的時間了，盧德米拉不知道回來了沒？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"응? 기타 소리……?","JPN":"うん？　ギターの音……？","ENG":"Hmm? Guitar sounds...?","TWN":"嗯？吉他聲……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"부, 부전대장님? 언제 오셨습니까?","JPN":"ふ、副戦隊長殿？　いつからいらっしゃったんですか？","ENG":"D-Deputy Commander? How long were you standing there?","TWN":"副，副戰隊長？你什麼時候來的？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"놀라게 했다면 미안해. 몰래 감상만 하려고 했는데.","JPN":"驚かせてしまってごめんなさい。こっそり聴くだけにしようと思っていたんだけれど。","ENG":"Sorry if I startled you. I was going to listen quietly so you wouldn't notice.","TWN":"抱歉嚇到你，我本來只是想默默欣賞而已。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"처음 들어보는 멜로디네. 발레리 네가 직접 지은 거니?","JPN":"そのメロディーは初めて聞くわ。ヴァレリーが自分で書いたの？","ENG":"I've never heard that melody before. Did you come up with it, Valeriy?","TWN":"沒聽過的旋律呢？是你自己做的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"하하, 그렇게 대단한 건 아니고 손 가는 대로 쳐 본 겁니다.","JPN":"はは、そんなに大層なものじゃないですよ、なんとなく気の向くまま弾いていただけで。","ENG":"Hah hah, it's nothing great. I was just improvising.","TWN":"哈哈，沒這麼厲害啦，只是隨手彈彈而已。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"멋진 곡이 될 것 같아. 나중에 완성되면 꼭 들려줘.","JPN":"素敵な曲になりそうね。完成したらぜひ聞かせてちょうだい。","ENG":"I think it'll turn out to be a great song. Play it for me when it's done.","TWN":"感覺會是一首很棒的曲子，完成後要彈給我聽喔。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"당연히 제일 먼저 들려드려야죠! 염려 붙들어 매십시오!","JPN":"もちろん一番最初にお聞かせします！　ご心配なく！","ENG":"Of course! You'll be the first to hear it! I promise!","TWN":"當然第一個就要彈給副戰隊長聽！放一百萬個心吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"후훗. 고마워, 발레리.","JPN":"ふふっ、ありがとう。ヴァレリー。","ENG":"Haha. Thanks, Valeriy.","TWN":"呵呵，謝啦，瓦萊里。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"오늘은 평소보다 일찍 왔네. 고생했어, 류드밀라.","JPN":"今日はいつもより早かったわね。お疲れ様、リュドミラ。","ENG":"You're back earlier than usual. You must be exhausted, Lyudmila.","TWN":"你今天來得比較早呢，辛苦囉，盧德米拉。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"부대 일을 전부 맡겨 놓고 간 입장에서 들을 말은 아니군.","JPN":"部隊の仕事を全部君に放り投げて行った身としては、そう言ってもらえる資格はないと思うが。","ENG":"I don't think I can complain after leaving you to manage the division.","TWN":"我把部隊的事都交給你，我有什麼好辛苦的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하필 훈련이 있는 날 자리를 비우다니… 전대장으로서 면목이 없다.","JPN":"よりによって訓練がある日に席を外すなんて……戦隊長として面目ない。","ENG":"Having to leave on training day... I am ashamed to be called your commander.","TWN":"而且偏偏還是在訓練的時候…身為戰隊長實在是非常羞愧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"괜찮아. 위에서 부르는데 당연히 다녀와야지.","JPN":"大丈夫よ。上部から呼び出しがあったんだから、行くのが当然でしょう。","ENG":"It's all right. You gotta go when your superior calls you.","TWN":"沒事，既然是上頭的吩咐，你當然要去一趟囉。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"내가 자리를 비운 동안 부대에 별일 없었나?","JPN":"私がいない間部隊には何もなかったか？","ENG":"Did anything particular happen while I was away?","TWN":"我不在的這段時間，隊上沒什麼事吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"흐음. 소소한 것 몇 가지 정도.","JPN":"うーん、些細なことならいくつか。","ENG":"Hmm... Just a few trivial things.","TWN":"嗯，都是些小事。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"며칠 전에 새로 온 아이가 폭발물을 잘못 건드려서 격납고 차단벽이 파손됐어.","JPN":"数日前、新しく入ってきた子がうっかり爆発物を爆発させてしまって、格納庫のシャッターが破損したわ。","ENG":"The rookie who joined a few days ago mishandled the explosives, destroying the hangar's shutter door.","TWN":"幾天前新來的孩子不小心誤觸炸彈，結果炸毀機艙的隔間。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"폭발물을 취급할 만한 부대원이라면…… 다닐이? 생명에 지장은 없나?","JPN":"爆発物を取り扱える部隊員といえば……ダニールか？　命に別状は？","ENG":"Someone who would be handling the explosives is... Danil? Is he all right?","TWN":"可以碰到炸彈的隊員……是丹尼爾？他還好嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"일단은 생채기만 생긴 정도야.","JPN":"ひとまず軽い怪我程度で済んだわ。","ENG":"Just a few scratches here and there.","TWN":"就一些皮肉傷。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"뭐, 다른 애들한테 훈련용 폭발물 때문에 허둥댔다고 한동안은 놀림 좀 받으려나.","JPN":"まぁ、他の子どもたちから訓練用の爆発物もまともに扱えないってしばらくからかわれるでしょうけどね。","ENG":"But I bet the others are gonna tease him for mishandling the training explosives for a while.","TWN":"然後被其他人嘲笑，說只是訓練用的炸彈就嚇成這樣。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"훈련용이라도 폭발물은 폭발물이다. 위험 물질 취급 교육을 다시 해야겠어.","JPN":"訓練用とはいえ爆発物が爆発物であることに変わりはない。危険物取り扱いの教育をしなおさなくては。","ENG":"An explosive is still an explosive. Perhaps we need to reeducate everyone on how to handle dangerous material.","TWN":"不管是不是訓練用的，炸彈就是炸彈。看來必須重新教育大家如何處理危險物品。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그건 좀 참아 주면 좋겠네. 부관으로서 하는 충고인데 넌 연설 실력부터 쌓아야 해.","JPN":"それは我慢してくれるとありがたいわね。副官としての忠告だけど、あなたは演説の練習からした方がいいわ。","ENG":"You might want to put a pin in that. As Deputy Commander, I'd advise that you work on your speech skills before doing that.","TWN":"你還是先忍忍吧。作為你的副手，我勸你先從累積演講實力開始。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……부대원들이 그러던가?","JPN":"……部隊員たちがそう言っていたのか？","ENG":"...Did one of the members say that to you?","TWN":"……隊員們有什麼意見嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"누가 말했는지는 비밀로 할게. 익명성을 보장해 줘야지.","JPN":"誰が言っていたのかは伏せておくわ。匿名性は保証してあげないとね。","ENG":"I won't tell. I gotta keep it anonymous, you know.","TWN":"我不能告訴你是誰說的，我必須保護證人。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"보자, 다음으로는…… 아. 예고르가 오늘 훈련을 무단으로 빠지려고 했어.","JPN":"それじゃあ、あとは……あ、イェゴールが今日の訓練をさぼろうとしたって話。","ENG":"Let's see. What else... Oh. Yegor tried to skip training today without permission.","TWN":"繼續吧，接下來是……伊高爾，他今天無故缺席訓練。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"예고르가 말인가?","JPN":"イェゴールが？","ENG":"Yegor?","TWN":"伊高爾？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"응. 함교 위에 숨어서 하모니카를 불고 있더라. 시간 가는 줄도 모르고.","JPN":"そう。艦橋の上に隠れてハーモニカを吹いていたの。時間も忘れて。","ENG":"Yeah. He was hiding on the bridge playing his harmonica without a care in the world.","TWN":"嗯，他躲在艦橋上吹口琴，吹到忘記時間。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"으음…….","JPN":"ううむ……","ENG":"Mm...","TWN":"嗯嗯……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그리고 보급고에 있던 보충제가 도난당했어. 나가기 전에 꼼꼼하게 점검했는데도 말이야.","JPN":"あと補給庫にあったサプリメントが盗まれたわ。倉庫を出る前にきっちり点検したにも関わらずね。","ENG":"Also, the supplements in storage were stolen. Even after I checked thoroughly before leaving.","TWN":"還有倉庫的補充品遭竊，但我離開前明明有清點過。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그 건이라면 더 듣지 않아도 알겠군. 발레리겠지.","JPN":"その件に関してはそれ以上聞かなくても察しがつく。ヴァレリーだろうな。","ENG":"I don't need to hear more of that. It must be Valeriy.","TWN":"這個不用說也知道是瓦萊里幹的好事。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"맞아. 이번에도 자기 관물대에 숨겨 뒀지. 언제나 되어야 다른 데에 숨기려나.","JPN":"当たり。今回も自分のロッカーに隠していたわ。いつになったら隠す場所を変えるのかしらね。","ENG":"Yup. He hid them again in his locker. I wonder when he'll choose a different place to hide them.","TWN":"沒錯，他這次也藏在自己的儲藏櫃裡，怎麼都不會換個地方藏？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그런 허술한 점은 발레리답군.","JPN":"そういう詰めが甘いところはヴァレリーらしいな。","ENG":"Such a flaw is what makes Valeriy Valeriy.","TWN":"瓦萊里就是這樣粗線條。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"같은 생각이야. 마중 나오는 길에 보니까 벌써 아무렇지 않게 기타 연습 중이더라.","JPN":"そうね。迎えに来る途中で見たんだけど、もう何事もなかったかのようにキターを練習してたわ。","ENG":"I think so too. Even when I was on my way to see you, he was casually practicing on his guitar.","TWN":"沒錯，我出來接你時有看到他，他已經若無其事地在彈吉他了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"안색이 안 좋네, 류드밀라? 열이라도 있니?","JPN":"顔色が悪いわね、リュドミラ？　熱でもあるの？","ENG":"You don't look so good, Lyudmila. Do you have a fever?","TWN":"盧德米拉，你臉色不太好？是發燒了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"발레리도, 예고르도 알렉스 너와 같은 처지 아닌가.","JPN":"ヴァレリーもイェゴールもアレックス、君と同じ境遇ではないか。","ENG":"Aren't Valeriy and Yegor in the same circumstances as you, Alex?","TWN":"瓦萊里、伊高爾，他們也和你一樣不是嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"악기를 다루는 모습이 보기 싫다면…….","JPN":"楽器を弾いている姿が見たくないなら……","ENG":"If you don't like seeing them with instruments–","TWN":"要是你不喜歡他玩樂器……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"읍.","JPN":"うぶ。","ENG":"Mmf.","TWN":"唔。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"내가 평소에 그렇게 속 좁은 사람으로 보였던 걸까, 전대장님?","JPN":"私がそんな心の狭い人間に見えていたのかしら、戦隊長？","ENG":"Do you always think of me as someone that petty, Commander?","TWN":"在戰隊長眼裡，我平時是這麼小心眼的人嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……상관의 뺨을 꼬집는 건 하극상이다, 부전대장.","JPN":"……上官の頬をつねるのは下剋上だぞ、副戦隊長。","ENG":"...Deputy Commander, pinching my cheeks is a serious assault on your superior officer.","TWN":"……捏長官的臉是以下犯上，副戰隊長。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"후훗. 그럼 다행이네. 여긴 우리 둘뿐이라서.","JPN":"ふふっ。ならよかったわ。ここには私たち二人しかいないもの。","ENG":"Haha. Well, then I'm glad it's just the two of us right now.","TWN":"呵呵，好險這裡只有我們二個。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"자리 비운 동안 들어온 보고서는 자리에 가져다 뒀어.","JPN":"ここにいない間に提出された報告書は席に置いておいたわ。","ENG":"I put all the reports that came in while you were away on your desk.","TWN":"你不在的這段時間收到的報告，都已經放在你桌上了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"점호 돌고 올 동안 찬찬히 살펴봐.","JPN":"点呼してくるから、ゆっくり見ておいてね。","ENG":"Take a look at them while I do a roll call.","TWN":"我先去晚點名了，你慢慢看吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……그러지. 알렉스.","JPN":"……了解した。アレックス。","ENG":"...I will, Alex.","TWN":"……好，你去吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"subtitle","speaker":null,"text":{"KOREA":"점호","JPN":"点呼","ENG":"Roll call","TWN":"晚點名"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"다들 좋은 꿈 꿔, 얘들아.","JPN":"良い夢を見てね、みんな。","ENG":"Sweet dreams, kids.","TWN":"大家晚安。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"음? 알렉스, 이 시각에 일어났나?","JPN":"うん？　アレックス、こんな時間になぜ起きている？","ENG":"Mm? Alex, why are you up at this hour?","TWN":"嗯？雅蕾克絲，你怎麼這麼早起床？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그러는 류드밀라 너야말로. 왠지 섭섭하네.","JPN":"そういうリュドミラこそ。なんか寂しいわね。","ENG":"I should ask you the same thing, Lyudmila. I'm kinda bummed about it too.","TWN":"盧德米拉，你才是吧？我心裡有點不是滋味呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"예전에는 도무지 침대를 못 벗어나던 늦잠꾸러기라 돌봐 주는 보람이 있었는데.","JPN":"昔はベットにしがみついてなかなか起きてくれない寝坊助だったから世話のし甲斐があったのに。","ENG":"It was rewarding to take care of old, sleepyhead Lyudmila back in the day.","TWN":"以前你都會賴床，怎麼叫都叫不醒，都需要我叫你起床的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"……작전기록 녹음. 부전대장의 인신공격이 거세다.","JPN":"……作戦記録、録音。副戦隊長からの誹謗中傷が激しい。","ENG":"...Operation log. Deputy Commander's personal attacks on me are scathing.","TWN":"……作戰紀錄錄音。副戰隊長對我的人身攻擊很強烈。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L28_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"후훗. 부끄러워하지 않아도 돼. 한창 어릴 때였잖아.","JPN":"ふふっ。恥ずかしがらなくていいのよ。ずっと小さい頃の話だもの。","ENG":"Haha. Don't be so embarrassed. You were really young back then.","TWN":"呵呵，幹嘛害羞，那時候你還小的嘛。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그 때와 달라진 건 없지만 말이지.","JPN":"あの頃と何一つ変わっていないけどね。","ENG":"But I haven't changed much since then.","TWN":"現在好像也沒什麼長進。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"다른 부대원들이 기상하려면 꽤 기다려야 할 거다.","JPN":"他の部隊員たちが起床するのはかなり先だ。","ENG":"It will be a while before the other members wake up.","TWN":"其他人應該還需要一段時間才會起床吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"부대 관리로 피곤할 텐데 조금 더 눈을 붙이는 게 어떻겠나.","JPN":"部隊の管理で疲れているだろうし、もう少し寝ておいた方がいいのではないか。","ENG":"Managing the troops must be tiring. Why don't you get some rest while you can?","TWN":"管理部隊應該很累吧？不如再多睡一下？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"제안은 고맙지만 괜찮아. 할일이 있어서 일찍 일어났거든.","JPN":"ご提案には感謝するけど、早起きしたのには訳があるの。","ENG":"Thanks for the advice, but I'm good. I got up early to take care of some stuff anyway.","TWN":"謝謝你的建議，但我有事情要辦才這麼早起床的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯嗯……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알겠다. 하지만 너무 무리는 하지 말도록. 네가 없으면 부대원들도 쉽게 동요하니 말이다.","JPN":"わかった。しかしあまり無理はするな。君がいないと部隊員たちも簡単に動揺してしまう。","ENG":"Very well. But don't strain yourself. Because the others are easily shaken without you.","TWN":"好吧，但你不要太過勉強。你不在的話其他人也會動搖的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그럼. 우리 애들 두고 내가 어디 가겠어.","JPN":"もちろん。子どもたちを置いてどこにも行かないわよ。","ENG":"Of course. I'm not going anywhere without the kids.","TWN":"知道啦，我是要扔下他們去哪裡。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"갑판에 나가 있을게. 필요할 때 언제든 불러 줘.","JPN":"デッキに出ているわ。何かあったらいつでも呼んでちょうだい。","ENG":"I'll be on the deck. Call me if you need anything.","TWN":"我會在甲板那裡，有需要的話隨時叫我。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"……부전대장님?","JPN":"……副戦隊長殿？","ENG":"...Deputy Commander?","TWN":"……副戰隊長？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L42_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"응? 예고르네? 언제 왔니?","JPN":"あら？　イェゴール？　いつからいたの？","ENG":"Hmm? Oh, Yegor. When did you get here?","TWN":"嗯？是伊高爾？你什麼時候來的？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"방금 막 왔습니다. 익숙한 소리가 들려서요.","JPN":"ちょうど来たばかりです。懐かしい音がしたので。","ENG":"Just now. I heard a familiar tune.","TWN":"我才剛來而已。因為聽到熟悉的旋律。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"죄송합니다. 환청이라도 들은 줄 알았는데 부전대장님이셨군요.","JPN":"申し訳ありません。幻聴かと思ったのですが、副戦隊長殿だったんですね。","ENG":"I'm sorry. I thought I was hearing things, but it was you.","TWN":"很抱歉，我還以為是我幻聽，沒想到是副戰隊長。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"솔직하게 사과했으니까 용서해 줄게.","JPN":"素直に謝ったし、許すわ。","ENG":"I'll forgive you because of your sincere apology.","TWN":"看在你立刻道歉的份上，就原諒你吧。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"아직 미완성인 곡이야. 완성하려면 한참은 걸리려나.","JPN":"まだ未完成の曲よ。完成するのはまだまだ先かしら。","ENG":"The song's still incomplete. I think it's going to take some time before it's finished.","TWN":"這首曲子還沒完成，要完成應該還需要一些時間吧。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"괜찮습니다. 기다리는 것도 즐거움이죠.","JPN":"大丈夫です。待つことも楽しみのうちですからね。","ENG":"No worries. Waiting is also part of the fun.","TWN":"沒關係，等待也是種樂趣。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"정말 다들 넉살만 늘었다니까.","JPN":"本当に口だけはうまくなったわね。","ENG":"Everyone's so cheeky these days.","TWN":"大家真的都只有嘴上功夫有長進呢。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"다른 애들은?","JPN":"他のみんなは？","ENG":"What about the others?","TWN":"其他人呢？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"식사 마치고 대기 중입니다. 전대장님께서 부전대장님은 개인 정비 중이라고 하시더군요.","JPN":"食事を終えて待機しています。戦隊長殿が副戦隊長殿は個人的な支度中だとおっしゃっていましたので。","ENG":"They've finished eating and are on standby. Commander told me that you were doing some personal maintenance.","TWN":"大家吃完飯待命中。 戰隊長說副戰隊長自己在預備中。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"아, 시간이 벌써 그렇게 됐니?","JPN":"あら、もうそんな時間？","ENG":"Oh, look at the time!","TWN":"都這麼晚啦？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"곤란하네. 이렇게 오래 연습할 생각은 없었는데.","JPN":"困ったわね。こんなに長く練習するつもりはなかったのだけれど。","ENG":"How embarrassing. I wasn't thinking of practicing for this long.","TWN":"糟糕，我原本沒打算花這麼多時間練的。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"하하, 저도 그렇게 뭔가에 몰입하고 계신 부전대장님은 처음 봤습니다.","JPN":"はは、私もここまで何かに没頭している副戦隊長殿は初めて見ました。","ENG":"Ha ha, I think it's my first time seeing you focus on something that much, Deputy Commander.","TWN":"哈哈，我也是第一次看到副戰隊長這麼投入呢。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"몰입이라…….","JPN":"没頭か……","ENG":"Focus, eh...?","TWN":"投入喔……"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"예고르.","JPN":"イェゴール。","ENG":"Yegor.","TWN":"伊高爾。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"예, 부전대장님.","JPN":"はい、副戦隊長殿。","ENG":"Yes, Deputy Commander.","TWN":"是，副戰隊長。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"발레리는…… 왜 이 멜로디만 연주했던 걸까?","JPN":"ヴァレリーは……どうしてこのメロディーだけを繰り返し弾いていたんだと思う？","ENG":"Why do you think... Valeriy only played this melody?","TWN":"瓦萊里他……為什麼只彈這段曲子呢？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"곡은 완성도 못하고 말이야.","JPN":"曲を完成させることもできずに。","ENG":"And he didn't even finish writing the song.","TWN":"而且還是沒完成的曲子。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"잘은 모르지만, 고향이 생각나는 음이라 더 소중히 다루게 된다고 했던 건 기억합니다.","JPN":"よくはわかりませんが、故郷を思い出させてくれるメロディーだからこそ、慎重になると言っていたことを覚えています。","ENG":"I'm not sure, but I remember him cherishing it because he said the notes reminded him of home.","TWN":"我也不太清楚，我只記得他說過，這首曲子會讓他想起家鄉。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"……바보 같은 녀석이죠. 우리에게 고향 같은 게 어디 있다고.","JPN":"……ばかですよね。私たちに故郷なんかあるわけないのに。","ENG":"...Stupid, I know. We don't have a home, after all.","TWN":"……很傻對吧，我們哪還有什麼家鄉可言。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"글쎄, 마음의 안식처 아닐까?","JPN":"どうかしらね、心の拠り所なんじゃないかしら？","ENG":"Who knows? Maybe it was his inner oasis?","TWN":"可能是指心裡的安息處吧？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"연주하면서 느꼈는데…… 이 곡. 왠지 우리들이랑 닮았거든.","JPN":"弾いていて気づいたんだけれど……この曲、なんだか私たちに似ているのよ。","ENG":"As I was playing it... I felt that this song resembles us in some way.","TWN":"不知道為什麼……我彈的時候覺得這首曲子跟我們很像。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"발레리도 나와 같은 기분이었다면, 이 곡을 연주할 때마다 우릴 떠올렸겠지.","JPN":"ヴァレリーも私と同じような気持ちだったなら、この曲を弾くたびに私たちを思い出していたのでしょうね。","ENG":"If Valeriy felt the same thing as I did, I bet he thought of us every time he played it.","TWN":"若是瓦萊里也跟我有相同的感受，那每當他彈奏這首曲子時就會想起我們吧？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"내가 이 곡을 연주하면서 발레리를 떠올리는 것처럼.","JPN":"私がこの曲を弾きながらヴァレリーを思い出すように。","ENG":"Just like how I think of him whenever I play it.","TWN":"就像我彈奏這首曲子時也會想起他一樣。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"……감상적인 이야기군요.","JPN":"……感傷的なお話ですね。","ENG":"...That's touching.","TWN":"……真是感傷。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"그 녀석, 부전대장님이 자기 곡을 아껴 주신다는 걸 알면 좋아서 어쩔 줄 몰라 할 겁니다.","JPN":"あいつ、副戦隊長殿が自分の曲を大事にしてくだっていることを知れば、喜んでぴょんぴょん飛び跳ねるでしょうね。","ENG":"I'm sure he'd be more than thrilled if he knew how much you cared about his song, Deputy Commander.","TWN":"那傢伙要是知道副戰隊長如此愛惜自己的曲子，一定會開心到手足無措。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그 말을 들었더니 어깨가 무거워지네. 완벽하게 완성해야겠어.","JPN":"それを聞いて肩の荷が重くなった気がするわ。完璧に仕上げないとね。","ENG":"Hearing that just made my shoulders heavy. I now must perfect this song.","TWN":"你這麼一說我反而很有壓力呢，那我必須要讓這首曲子聽起來很完美才行。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그러니까 예고르, 앞으로 연습하는 소리가 들려도 모르는 척 하기야?","JPN":"だからイェゴール、これからも練習の音が聞こえてきても知らないふりしてくれるわね？","ENG":"So, Yegor. Please pretend you don't hear me practicing from now on.","TWN":"伊高爾，之後你要是聽到我在練習，要假裝沒聽到喔？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"그럼요. 염려 붙들어 매십시오.","JPN":"はいもちろん。ご心配無用です。","ENG":"Of course. You don't have to worry about that.","TWN":"沒問題，盡管放心。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_GREATSWORD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};